def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        power_terms = []
        for j in range(1, 15):
            if j % 3 == 0:
                factor = 1.2
            elif j % 2 == 0:
                factor = 1.1
            else:
                factor = 0.8
            term = factor * (1 / (j**2)) * (ratio ** j)
            power_terms.append(term)
        score = sum(power_terms)
        remaining = capacity - item
        if remaining < 0.03 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.5
        elif remaining < 0.2 * capacity:
            score *= 1.1
        else:
            score *= 0.75
        mod3 = int(capacity) % 3 == 0
        mod5 = int(capacity) % 5 == 0
        mod7 = int(capacity) % 7 == 0
        if mod3 and mod5:
            score -= 0.12 * (capacity / 8)
        elif mod5 and mod7:
            score -= 0.18 * (capacity / 15)
        elif mod3 and mod7:
            score -= 0.1 * (capacity / 20)
        elif mod3:
            score -= 0.05 * (capacity / 10)
        elif mod5:
            score -= 0.1 * (capacity / 20)
        elif mod7:
            score -= 0.07 * (capacity / 25)
        else:
            score -= 0.03 * (capacity / 30)
        penalty = 0
        for k in range(1, 6):
            diff = abs(capacity - item * k)
            threshold = 0.015 * capacity * k
            if diff < threshold:
                penalty += 0.25 * k
            elif diff < 2 * threshold:
                penalty += 0.1 * k
            else:
                penalty -= 0.05 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 1.5:
            for m in range(1, 4):
                if abs((capacity / m) - item) < 0.02 * (capacity / m):
                    score *= (1 + 0.05 * m)
        priorities[i] = score
    return priorities
